INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0602134A$$, 2027, $$This PE executes applied research into novel methods for the detection and classification complex obstacles, including new advanced surface-laid and buried anti-
personnel mines, anti-tank mines, off-route effectors, wire, anti-vehicle obstacles, and other threat constructed obstacles under the expected environmental conditions in
Large Scale Combat Operations (LSCO) to enable application to maneuver and breaching.

 This PE is executed in coordination with the Under Secretary of War for Research and Engineering and the Defense Threat Reduction Agency (DTRA).

 Work in this PE is fully coordinated with PE 0603134A (Counter Improvised Threat Simulation), Project CD3 (Counter Improvised Threat Simulation).

 Work in this project is managed by Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center. Work is
 performed by the U.S. Army Combat Capabilities Development Command (DEVCOM), Army Artificial Intelligence Integration Center (AI2C), the Engineering Research
 and Development Center, Space and Missile Defense Technical Center, and the U.S. Army Research Institute for the Behavioral and Social Sciences with oversight
